source("ars.R")
set.seed(42)
# Override the ars function to add debugging
debug_ars <- function(n, f, lb = -Inf, ub = Inf, x_init = NULL) {
  validate_inputs(n, f, lb, ub, x_init)
  if (is.null(x_init)) x_init <- choose_initial_abscissae(f, lb, ub)
  x_abs <- sort(unique(x_init))
  h_vals <- eval_log_density(f, x_abs)
  if (!check_log_concavity(h_vals, x_abs)) stop("Not log-concave")
  upper_hull <- build_upper_hull(h_vals, x_abs, lb, ub)
  samples <- numeric(n)
  count <- 0
  max_iter <- n * 100
  iter <- 0
  while (count < n && iter < max_iter) {
    iter <- iter + 1
    proposal <- tryCatch(sample_upper_hull(upper_hull), error = function(e) {
      cat("sample_upper_hull error at iter", iter, "nabs=", length(x_abs), ":", e$message, "\n")
      return(NULL)
    })
    if (is.null(proposal)) break
    x_star <- proposal$x
    u_x_star <- proposal$u_x
    if (is.na(x_star) || is.na(u_x_star) || is.nan(x_star) || is.nan(u_x_star)) {
      cat("NaN at iter", iter, "x_star=", x_star, "u_x=", u_x_star, "nabs=", length(x_abs), "\n")
      break
    }
    w <- runif(1)
    l_x_star <- eval_lower_hull(x_star, h_vals, x_abs)
    if (is.na(l_x_star) || is.nan(l_x_star)) {
      cat("lower hull NaN at iter", iter, "\n")
    }
    lw <- log(w)
    diff_l <- l_x_star - u_x_star
    if (is.na(diff_l)) {
      cat("diff_l NA at iter", iter, "l=", l_x_star, "u=", u_x_star, "\n")
      break
    }
    if (lw <= diff_l) {
      count <- count + 1
      samples[count] <- x_star
    } else {
      h_x_star <- eval_log_density(f, x_star)
      if (is.na(h_x_star)) {
        cat("h_x_star NA at iter", iter, "\n")
        break
      }
      if (lw <= h_x_star - u_x_star) {
        count <- count + 1
        samples[count] <- x_star
      }
      ins_pos <- findInterval(x_star, x_abs) + 1
      x_abs <- append(x_abs, x_star, after = ins_pos - 1)
      h_vals <- append(h_vals, h_x_star, after = ins_pos - 1)
      if (!check_log_concavity(h_vals, x_abs)) stop("concavity violated")
      upper_hull <- tryCatch(build_upper_hull(h_vals, x_abs, lb, ub), error = function(e) {
        cat("build error at iter", iter, "nabs=", length(x_abs), ":", e$message, "\n")
        return(NULL)
      })
      if (is.null(upper_hull)) break
    }
  }
  cat("Generated", count, "out of", n, "\n")
}
