###############################################################################
# Adaptive Rejection Sampling (ARS)
# Based on: Gilks, W. R., & Wild, P. (1992). Adaptive rejection sampling
#           for Gibbs sampling. JRSS Series C, 41(2), 337-348.
#
# File: /app/ars.R
###############################################################################

# --------------------------------------------------------------------------- #
# Helper: evaluate log-density safely (vectorized)
# --------------------------------------------------------------------------- #
eval_log_density <- function(f, x) {
  fx <- f(x)
  if (any(is.nan(fx) | is.na(fx))) {
    stop("Density function returned NaN/NA values.")
  }
  if (any(fx < 0)) {
    stop("Density function returned negative values. Density must be non-negative.")
  }
  log_fx <- ifelse(fx > 0, log(fx), -Inf)
  return(log_fx)
}

# --------------------------------------------------------------------------- #
# Helper: check log-concavity at the current abscissae
# --------------------------------------------------------------------------- #
check_log_concavity <- function(h_vals, x_vals) {
  n <- length(x_vals)
  if (n < 3) return(TRUE)
  # Secant slopes between consecutive points
  dh <- diff(h_vals) / diff(x_vals)
  # Log-concavity requires non-increasing slopes
  for (i in 2:length(dh)) {
    if (is.finite(dh[i]) && is.finite(dh[i - 1])) {
      if (dh[i] > dh[i - 1] + 1e-6) {
        return(FALSE)
      }
    }
  }
  return(TRUE)
}

# --------------------------------------------------------------------------- #
# Helper: remove near-duplicate abscissae to avoid numerical issues
# --------------------------------------------------------------------------- #
deduplicate_abscissae <- function(x_vals, h_vals, tol = 1e-10) {
  keep <- rep(TRUE, length(x_vals))
  for (i in 2:length(x_vals)) {
    if (abs(x_vals[i] - x_vals[i - 1]) < tol) {
      keep[i] <- FALSE
    }
  }
  list(x = x_vals[keep], h = h_vals[keep])
}

# --------------------------------------------------------------------------- #
# Helper: build the upper hull using secant-based tangent approximation
#
# Uses the formulation from Gilks & Wild (1992):
# - For interior points j (2..k-1), the "tangent" slope at x_j is approximated
#   by the slope of the line from (x_{j-1}, h_{j-1}) to (x_{j+1}, h_{j+1}).
# - For endpoint j=1: slope of secant to x_2.
# - For endpoint j=k: slope of secant from x_{k-1}.
#
# The intersection points z_j between consecutive tangent lines define the
# piecewise domains.
# --------------------------------------------------------------------------- #
build_upper_hull <- function(h_vals, x_vals, lb, ub) {
  k <- length(x_vals)
  if (k < 2) stop("Need at least 2 abscissae to build the envelope.")

  # Secant slopes between consecutive points
  sec <- diff(h_vals) / diff(x_vals)

  # Approximate derivative at each abscissa
  hprime <- numeric(k)
  if (k == 2) {
    hprime[1] <- sec[1]
    hprime[2] <- sec[1]
  } else {
    hprime[1] <- sec[1]
    hprime[k] <- sec[k - 1]
    for (j in 2:(k - 1)) {
      # Use slope through (x_{j-1}, h_{j-1}) and (x_{j+1}, h_{j+1})
      hprime[j] <- (h_vals[j + 1] - h_vals[j - 1]) / (x_vals[j + 1] - x_vals[j - 1])
    }
  }

  # Check boundary conditions for integrability
  if (is.infinite(lb) && lb < 0) {
    if (!is.finite(hprime[1]) || hprime[1] <= 0) {
      stop("Log-density must have positive slope at the leftmost abscissa when lb = -Inf.")
    }
  }
  if (is.infinite(ub) && ub > 0) {
    if (!is.finite(hprime[k]) || hprime[k] >= 0) {
      stop("Log-density must have negative slope at the rightmost abscissa when ub = Inf.")
    }
  }

  # Tangent lines: u_j(x) = h_j + hprime_j * (x - x_j) = intercept_j + slope_j * x
  slopes <- hprime
  intercepts <- h_vals - hprime * x_vals

  # Intersection points z between consecutive tangent lines
  z <- numeric(k + 1)
  z[1] <- lb
  z[k + 1] <- ub
  for (j in seq_len(k - 1)) {
    denom <- slopes[j] - slopes[j + 1]
    if (!is.finite(denom) || abs(denom) < 1e-15) {
      z[j + 1] <- (x_vals[j] + x_vals[j + 1]) / 2
    } else {
      z_candidate <- (intercepts[j + 1] - intercepts[j]) / denom
      if (!is.finite(z_candidate)) {
        z[j + 1] <- (x_vals[j] + x_vals[j + 1]) / 2
      } else {
        z[j + 1] <- z_candidate
      }
    }
  }

  return(list(slopes = slopes, intercepts = intercepts, z = z))
}

# --------------------------------------------------------------------------- #
# Helper: evaluate the lower hull (chord through consecutive abscissae)
# --------------------------------------------------------------------------- #
eval_lower_hull <- function(x, h_vals, x_vals) {
  k <- length(x_vals)
  if (x < x_vals[1] || x > x_vals[k]) return(-Inf)
  j <- findInterval(x, x_vals, rightmost.closed = TRUE)
  if (j == 0) j <- 1
  if (j >= k) j <- k - 1
  dx <- x_vals[j + 1] - x_vals[j]
  if (abs(dx) < 1e-15) return(h_vals[j])
  t <- (x - x_vals[j]) / dx
  return((1 - t) * h_vals[j] + t * h_vals[j + 1])
}

# --------------------------------------------------------------------------- #
# Helper: sample from the piecewise-exponential upper envelope
# --------------------------------------------------------------------------- #
sample_upper_hull <- function(upper_hull) {
  slopes <- upper_hull$slopes
  intercepts <- upper_hull$intercepts
  z <- upper_hull$z
  k <- length(slopes)

  # Compute log of the integral of exp(s*x + c) on each piece [a, b]
  log_areas <- numeric(k)
  for (j in 1:k) {
    a <- z[j]
    b <- z[j + 1]
    s <- slopes[j]
    c_val <- intercepts[j]

    if (is.infinite(a) && a < 0) {
      log_areas[j] <- c_val + s * b - log(s)
    } else if (is.infinite(b) && b > 0) {
      log_areas[j] <- c_val + s * a - log(-s)
    } else if (abs(s) < 1e-15) {
      log_areas[j] <- c_val + log(b - a)
    } else {
      # log(integral) = c + s*a + log(|expm1(s*(b-a))|) - log(|s|)
      delta <- s * (b - a)
      if (abs(delta) < 1e-10) {
        # Taylor approximation for small delta
        log_areas[j] <- c_val + s * (a + b) / 2 + log(b - a)
      } else {
        log_areas[j] <- c_val + s * a + log(abs(expm1(delta))) - log(abs(s))
      }
    }
  }

  # Filter out non-finite log_areas (shouldn't happen, but safety)
  valid <- is.finite(log_areas)
  if (!any(valid)) stop("All envelope pieces have non-finite area.")

  # Normalize to get probabilities
  max_log <- max(log_areas[valid])
  areas <- rep(0, k)
  areas[valid] <- exp(log_areas[valid] - max_log)
  probs <- areas / sum(areas)

  # Sample which piece
  j <- sample.int(k, size = 1, prob = probs)

  a <- z[j]
  b <- z[j + 1]
  s <- slopes[j]
  u <- runif(1)

  if (is.infinite(a) && a < 0) {
    x_star <- b + log(u) / s
  } else if (is.infinite(b) && b > 0) {
    x_star <- a + log(1 - u) / s
  } else if (abs(s) < 1e-15) {
    x_star <- a + u * (b - a)
  } else {
    delta <- s * (b - a)
    if (abs(delta) < 1e-10) {
      x_star <- a + u * (b - a)
    } else {
      x_star <- a + log(1 + u * expm1(delta)) / s
    }
  }

  # Evaluate upper hull at x_star
  u_x <- s * x_star + intercepts[j]
  return(list(x = x_star, u_x = u_x))
}

# --------------------------------------------------------------------------- #
# Helper: validate inputs
# --------------------------------------------------------------------------- #
validate_inputs <- function(n, f, lb, ub, x_init) {
  if (!is.numeric(n) || length(n) != 1 || n < 1 || n != floor(n)) {
    stop("'n' must be a positive integer.")
  }
  if (!is.function(f)) {
    stop("'f' must be a function.")
  }
  if (!is.numeric(lb) || length(lb) != 1) {
    stop("'lb' must be a single numeric value.")
  }
  if (!is.numeric(ub) || length(ub) != 1) {
    stop("'ub' must be a single numeric value.")
  }
  if (lb >= ub) {
    stop("'lb' must be less than 'ub'.")
  }
  if (!is.null(x_init)) {
    if (!is.numeric(x_init) || length(x_init) < 2) {
      stop("'x_init' must be a numeric vector with at least 2 elements.")
    }
    if (any(x_init <= lb) || any(x_init >= ub)) {
      stop("All initial abscissae must be strictly inside (lb, ub).")
    }
  }
}

# --------------------------------------------------------------------------- #
# Helper: choose initial abscissae automatically
# --------------------------------------------------------------------------- #
choose_initial_abscissae <- function(f, lb, ub, n_init = 5) {
  left <- if (is.infinite(lb)) -10 else lb + 0.01 * abs(ub - lb)
  right <- if (is.infinite(ub)) 10 else ub - 0.01 * abs(ub - lb)
  if (is.infinite(lb) && is.infinite(ub)) { left <- -10; right <- 10 }

  grid <- seq(left, right, length.out = max(n_init * 10, 50))
  fvals <- f(grid)
  pos_idx <- which(fvals > 0)

  if (length(pos_idx) < 2) {
    stop("Could not find at least 2 points where f(x) > 0 in the search range.")
  }

  sel <- pos_idx[seq(1, length(pos_idx), length.out = min(n_init, length(pos_idx)))]
  x_init <- grid[sel]

  mode_idx <- which.max(fvals)
  mode_x <- grid[mode_idx]
  if (!(mode_x %in% x_init) && fvals[mode_idx] > 0) {
    x_init <- sort(unique(c(x_init, mode_x)))
  }

  return(x_init)
}

# --------------------------------------------------------------------------- #
# Main function: Adaptive Rejection Sampling
# --------------------------------------------------------------------------- #
ars <- function(n, f, lb = -Inf, ub = Inf, x_init = NULL) {
  # --- Input Validation --- #
  validate_inputs(n, f, lb, ub, x_init)

  # --- Choose initial abscissae if not provided --- #
  if (is.null(x_init)) {
    x_init <- choose_initial_abscissae(f, lb, ub)
  }
  x_init <- sort(unique(x_init))

  # --- Initialize --- #
  x_abs <- x_init
  h_vals <- eval_log_density(f, x_abs)

  # --- Check initial log-concavity --- #
  if (!check_log_concavity(h_vals, x_abs)) {
    stop("Density does not appear to be log-concave based on initial abscissae.")
  }

  # --- Build initial upper hull --- #
  upper_hull <- build_upper_hull(h_vals, x_abs, lb, ub)

  # --- Sampling loop --- #
  samples <- numeric(n)
  count <- 0
  max_iter <- n * 100
  iter <- 0

  while (count < n && iter < max_iter) {
    iter <- iter + 1

    # Step 1: Sample from upper envelope
    proposal <- sample_upper_hull(upper_hull)
    x_star <- proposal$x
    u_x_star <- proposal$u_x

    # Safety: skip NaN proposals
    if (!is.finite(x_star) || !is.finite(u_x_star)) next

    # Step 2: Squeeze test
    w <- runif(1)
    l_x_star <- eval_lower_hull(x_star, h_vals, x_abs)

    if (is.finite(l_x_star) && log(w) <= l_x_star - u_x_star) {
      count <- count + 1
      samples[count] <- x_star
      next
    }

    # Step 3: Rejection test — evaluate h(x*)
    h_x_star <- eval_log_density(f, x_star)

    if (log(w) <= h_x_star - u_x_star) {
      count <- count + 1
      samples[count] <- x_star
    }

    # Step 4: Update abscissae (only if h is finite — skip zero-density points)
    if (is.finite(h_x_star)) {
      ins_pos <- findInterval(x_star, x_abs) + 1
      x_abs <- append(x_abs, x_star, after = ins_pos - 1)
      h_vals <- append(h_vals, h_x_star, after = ins_pos - 1)

      # Remove near-duplicates for numerical stability
      dedup <- deduplicate_abscissae(x_abs, h_vals)
      x_abs <- dedup$x
      h_vals <- dedup$h

      # Step 5: Check log-concavity
      if (!check_log_concavity(h_vals, x_abs)) {
        stop("Log-concavity violated after adding a new point. The density is not log-concave.")
      }

      # Step 6: Rebuild upper hull
      upper_hull <- build_upper_hull(h_vals, x_abs, lb, ub)
    }
  }

  if (count < n) {
    warning(paste("Only generated", count, "out of", n, "requested samples."))
    samples <- samples[1:count]
  }

  return(samples)
}

# --------------------------------------------------------------------------- #
# Test function: formal testing with known distributions
# --------------------------------------------------------------------------- #
test <- function() {
  cat("============================================\n")
  cat("  Adaptive Rejection Sampler - Test Suite\n")
  cat("============================================\n\n")

  pass_count <- 0
  fail_count <- 0

  report <- function(name, passed, info = "") {
    if (passed) {
      cat(paste0(name, ": PASS"), "\n")
      pass_count <<- pass_count + 1
    } else {
      cat(paste0(name, ": FAIL"), "\n")
      fail_count <<- fail_count + 1
    }
    if (nchar(info) > 0) cat("  ", info, "\n")
  }

  # ---- Test 1: Standard Normal N(0,1) ---- #
  cat("--- Test 1: Standard Normal N(0,1) ---\n")
  set.seed(42)
  tryCatch({
    samples <- ars(n = 10000, f = dnorm, lb = -Inf, ub = Inf)
    m <- mean(samples); s <- sd(samples)
    cat(sprintf("  Sample mean = %.4f (expected ~0), SD = %.4f (expected ~1)\n", m, s))
    ks <- ks.test(samples, "pnorm")
    cat(sprintf("  KS test p-value = %.4f\n", ks$p.value))
    passed <- abs(m) < 0.1 && abs(s - 1) < 0.15 && ks$p.value > 0.01
    report("test_normal_distribution", passed,
           sprintf("mean=%.4f, sd=%.4f, ks_p=%.4f", m, s, ks$p.value))
    writeLines(as.character(samples), "/app/normal_samples.txt")
    cat("  Saved 10000 samples to /app/normal_samples.txt\n")
  }, error = function(e) {
    report("test_normal_distribution", FALSE, paste("Error:", e$message))
  })
  cat("\n")

  # ---- Test 2: Exponential(rate=1) ---- #
  cat("--- Test 2: Exponential(rate=1) ---\n")
  set.seed(42)
  tryCatch({
    samples <- ars(n = 10000, f = dexp, lb = 0, ub = Inf,
                   x_init = c(0.1, 1, 3, 5))
    m <- mean(samples); s <- sd(samples)
    cat(sprintf("  Sample mean = %.4f (expected ~1), SD = %.4f (expected ~1)\n", m, s))
    ks <- ks.test(samples, "pexp")
    cat(sprintf("  KS test p-value = %.4f\n", ks$p.value))
    passed <- abs(m - 1) < 0.15 && abs(s - 1) < 0.15 && ks$p.value > 0.01
    report("test_exponential_distribution", passed,
           sprintf("mean=%.4f, sd=%.4f, ks_p=%.4f", m, s, ks$p.value))
    writeLines(as.character(samples), "/app/exponential_samples.txt")
    cat("  Saved 10000 samples to /app/exponential_samples.txt\n")
  }, error = function(e) {
    report("test_exponential_distribution", FALSE, paste("Error:", e$message))
  })
  cat("\n")

  # ---- Test 3: Gamma(shape=3, rate=2) ---- #
  cat("--- Test 3: Gamma(shape=3, rate=2) ---\n")
  set.seed(42)
  tryCatch({
    f_gamma <- function(x) dgamma(x, shape = 3, rate = 2)
    samples <- ars(n = 10000, f = f_gamma, lb = 0, ub = Inf,
                   x_init = c(0.1, 0.5, 1, 2, 4))
    m <- mean(samples); s <- sd(samples)
    true_mean <- 3 / 2; true_sd <- sqrt(3) / 2
    cat(sprintf("  Sample mean = %.4f (expected ~%.4f), SD = %.4f (expected ~%.4f)\n",
                m, true_mean, s, true_sd))
    ks <- ks.test(samples, "pgamma", shape = 3, rate = 2)
    cat(sprintf("  KS test p-value = %.4f\n", ks$p.value))
    passed <- abs(m - true_mean) < 0.15 && abs(s - true_sd) < 0.15 && ks$p.value > 0.01
    report("test_gamma_distribution", passed,
           sprintf("mean=%.4f, sd=%.4f, ks_p=%.4f", m, s, ks$p.value))
  }, error = function(e) {
    report("test_gamma_distribution", FALSE, paste("Error:", e$message))
  })
  cat("\n")

  # ---- Test 4: Beta(2, 5) ---- #
  cat("--- Test 4: Beta(2, 5) ---\n")
  set.seed(42)
  tryCatch({
    f_beta <- function(x) dbeta(x, shape1 = 2, shape2 = 5)
    samples <- ars(n = 10000, f = f_beta, lb = 0, ub = 1,
                   x_init = c(0.1, 0.3, 0.5, 0.7, 0.9))
    m <- mean(samples); s <- sd(samples)
    true_mean <- 2 / 7; true_sd <- sqrt(2 * 5 / (49 * 8))
    cat(sprintf("  Sample mean = %.4f (expected ~%.4f), SD = %.4f (expected ~%.4f)\n",
                m, true_mean, s, true_sd))
    ks <- ks.test(samples, "pbeta", shape1 = 2, shape2 = 5)
    cat(sprintf("  KS test p-value = %.4f\n", ks$p.value))
    passed <- abs(m - true_mean) < 0.1 && abs(s - true_sd) < 0.1 && ks$p.value > 0.01
    report("test_beta_distribution", passed,
           sprintf("mean=%.4f, sd=%.4f, ks_p=%.4f", m, s, ks$p.value))
  }, error = function(e) {
    report("test_beta_distribution", FALSE, paste("Error:", e$message))
  })
  cat("\n")

  # ---- Test 5: Normal N(5, 4) ---- #
  cat("--- Test 5: Normal N(5, 4) ---\n")
  set.seed(42)
  tryCatch({
    f_norm <- function(x) dnorm(x, mean = 5, sd = 2)
    samples <- ars(n = 10000, f = f_norm, lb = -Inf, ub = Inf)
    m <- mean(samples); s <- sd(samples)
    cat(sprintf("  Sample mean = %.4f (expected ~5), SD = %.4f (expected ~2)\n", m, s))
    ks <- ks.test(samples, "pnorm", mean = 5, sd = 2)
    cat(sprintf("  KS test p-value = %.4f\n", ks$p.value))
    passed <- abs(m - 5) < 0.2 && abs(s - 2) < 0.3 && ks$p.value > 0.01
    report("test_normal_shifted", passed,
           sprintf("mean=%.4f, sd=%.4f, ks_p=%.4f", m, s, ks$p.value))
  }, error = function(e) {
    report("test_normal_shifted", FALSE, paste("Error:", e$message))
  })
  cat("\n")

  # ---- Test 6: Input validation — negative n ---- #
  cat("--- Test 6: Input validation (negative n) ---\n")
  tryCatch({
    ars(n = -5, f = dnorm)
    report("test_negative_n", FALSE, "Should have thrown an error")
  }, error = function(e) {
    report("test_negative_n", TRUE, paste("Caught:", e$message))
  })
  cat("\n")

  # ---- Test 7: Input validation — non-function f ---- #
  cat("--- Test 7: Input validation (non-function f) ---\n")
  tryCatch({
    ars(n = 100, f = "not_a_function")
    report("test_non_function_f", FALSE, "Should have thrown an error")
  }, error = function(e) {
    report("test_non_function_f", TRUE, paste("Caught:", e$message))
  })
  cat("\n")

  # ---- Test 8: Input validation — lb >= ub ---- #
  cat("--- Test 8: Input validation (lb >= ub) ---\n")
  tryCatch({
    ars(n = 100, f = dnorm, lb = 5, ub = 2)
    report("test_invalid_bounds", FALSE, "Should have thrown an error")
  }, error = function(e) {
    report("test_invalid_bounds", TRUE, paste("Caught:", e$message))
  })
  cat("\n")

  # ---- Test 9: Input validation — n = 0 ---- #
  cat("--- Test 9: Input validation (n = 0) ---\n")
  tryCatch({
    ars(n = 0, f = dnorm)
    report("test_zero_n", FALSE, "Should have thrown an error")
  }, error = function(e) {
    report("test_zero_n", TRUE, paste("Caught:", e$message))
  })
  cat("\n")

  # ---- Test 10: Non-log-concave detection (bimodal) ---- #
  cat("--- Test 10: Non-log-concave detection (bimodal) ---\n")
  tryCatch({
    f_bimodal <- function(x) 0.5 * dnorm(x, -3, 0.5) + 0.5 * dnorm(x, 3, 0.5)
    samples <- ars(n = 1000, f = f_bimodal, lb = -Inf, ub = Inf)
    report("test_non_log_concave", FALSE, "Should have detected non-log-concavity")
  }, error = function(e) {
    caught <- grepl("log-concav", e$message, ignore.case = TRUE) ||
              grepl("concav", e$message, ignore.case = TRUE)
    report("test_non_log_concave", caught, paste("Caught:", e$message))
  })
  cat("\n")

  # ---- Test 11: Module — eval_log_density ---- #
  cat("--- Test 11: Module test - eval_log_density ---\n")
  tryCatch({
    vals <- eval_log_density(dnorm, c(-1, 0, 1))
    expected <- dnorm(c(-1, 0, 1), log = TRUE)
    passed <- all(abs(vals - expected) < 1e-10)
    report("test_eval_log_density", passed,
           sprintf("max_diff=%.2e", max(abs(vals - expected))))
  }, error = function(e) {
    report("test_eval_log_density", FALSE, paste("Error:", e$message))
  })
  cat("\n")

  # ---- Test 12: Module — check_log_concavity ---- #
  cat("--- Test 12: Module test - check_log_concavity ---\n")
  tryCatch({
    x_t <- c(-2, -1, 0, 1, 2)
    concave_ok <- check_log_concavity(-x_t^2, x_t)
    convex_bad <- check_log_concavity(x_t^2, x_t)
    passed <- concave_ok && !convex_bad
    report("test_check_log_concavity", passed,
           sprintf("concave=%s, convex=%s", concave_ok, convex_bad))
  }, error = function(e) {
    report("test_check_log_concavity", FALSE, paste("Error:", e$message))
  })
  cat("\n")

  # ---- Test 13: Module — build_upper_hull ---- #
  cat("--- Test 13: Module test - build_upper_hull ---\n")
  tryCatch({
    x_t <- c(-2, -1, 0, 1, 2)
    h_t <- dnorm(x_t, log = TRUE)
    hull <- build_upper_hull(h_t, x_t, -Inf, Inf)
    has_slopes <- length(hull$slopes) == 5
    has_intercepts <- length(hull$intercepts) == 5
    has_z <- length(hull$z) == 6
    passed <- has_slopes && has_intercepts && has_z
    report("test_build_upper_hull", passed,
           sprintf("slopes=%d, intercepts=%d, z=%d",
                   length(hull$slopes), length(hull$intercepts), length(hull$z)))
  }, error = function(e) {
    report("test_build_upper_hull", FALSE, paste("Error:", e$message))
  })
  cat("\n")

  # ---- Test 14: Input validation — non-numeric n ---- #
  cat("--- Test 14: Input validation (non-numeric n) ---\n")
  tryCatch({
    ars(n = "abc", f = dnorm)
    report("test_non_numeric_n", FALSE, "Should have thrown an error")
  }, error = function(e) {
    report("test_non_numeric_n", TRUE, paste("Caught:", e$message))
  })
  cat("\n")

  # ---- Test 15: Input validation — x_init outside bounds ---- #
  cat("--- Test 15: Input validation (x_init outside bounds) ---\n")
  tryCatch({
    ars(n = 100, f = dnorm, lb = -1, ub = 1, x_init = c(-2, 0, 0.5))
    report("test_xinit_outside_bounds", FALSE, "Should have thrown an error")
  }, error = function(e) {
    report("test_xinit_outside_bounds", TRUE, paste("Caught:", e$message))
  })
  cat("\n")

  # ---- Test 16: Truncated Normal [0, Inf) ---- #
  cat("--- Test 16: Truncated Normal N(0,1) on [0, Inf) ---\n")
  set.seed(42)
  tryCatch({
    samples <- ars(n = 10000, f = dnorm, lb = 0, ub = Inf,
                   x_init = c(0.1, 0.5, 1, 2, 4))
    m <- mean(samples); s <- sd(samples)
    true_mean <- sqrt(2 / pi)
    cat(sprintf("  Sample mean = %.4f (expected ~%.4f), SD = %.4f\n", m, true_mean, s))
    passed <- abs(m - true_mean) < 0.15 && all(samples >= 0)
    report("test_truncated_normal", passed,
           sprintf("mean=%.4f, sd=%.4f, all_positive=%s", m, s, all(samples >= 0)))
  }, error = function(e) {
    report("test_truncated_normal", FALSE, paste("Error:", e$message))
  })
  cat("\n")

  # ---- Summary ---- #
  cat("============================================\n")
  cat(sprintf("  TOTAL: %d PASS, %d FAIL out of %d tests\n",
              pass_count, fail_count, pass_count + fail_count))
  cat("============================================\n")

  invisible(list(pass = pass_count, fail = fail_count))
}

