  hprime[1] <- sec[1]
  hprime[2] <- sec[1]
} else {
  hprime[1] <- sec[1]
  hprime[k] <- sec[k - 1]
  for (j in 2:(k - 1)) {
    # Use slope through (x_{j-1}, h_{j-1}) and (x_{j+1}, h_{j+1})
