raw_arguments.new_string:
# Secant slopes between consecutive points
dx <- diff(x_vals)
dh <- diff(h_vals)
sec <- ifelse(abs(dx) > 1e-15, dh / dx, 0)

# Approximate derivative at each abscissa
hprime <- numeric(k)
if (k == 2) {
  hprime[1] <- sec[1]
  hprime[2] <- sec[1]
} else {
  hprime[1] <- sec[1]
  hprime[k] <- sec[k - 1]
  for (j in 2:(k - 1)) {
    span <- x_vals[j + 1] - x_vals[j - 1]
    if (abs(span) > 1e-15) {
      hprime[j] <- (h_vals[j + 1] - h_vals[j - 1]) / span
    } else {
      hprime[j] <- sec[j - 1]
    }
  }
}
# Replace any non-finite derivatives with nearest finite secant
for (j in 1:k) {
  if (!is.finite(hprime[j])) {
    if (j > 1 && is.finite(sec[j - 1])) hprime[j] <- sec[j - 1]
    else if (j < k && is.finite(sec[j])) hprime[j] <- sec[j]
    else hprime[j] <- 0
  }
}
